import { FOCUSABLE_SELECTOR } from "../../utils/focusableSelector";
export function findPrevFocusable(element) {
    if (!element) {
        return undefined;
    }
    const listItemEl = element.closest("li");
    let prevElement = listItemEl.previousElementSibling;
    while (prevElement) {
        if (prevElement.querySelector(FOCUSABLE_SELECTOR)) {
            return prevElement.querySelector(FOCUSABLE_SELECTOR);
        }
        prevElement = prevElement.previousElementSibling;
    }
    const focusable = listItemEl.parentNode.querySelectorAll(FOCUSABLE_SELECTOR);
    return focusable[focusable.length - 1];
}
