import { DESKTOP_PREFIX, TABLET_PREFIX, MOBILE_PREFIX, GRID_COL_PREFIX } from "./constants";
const gridClassPrefixes = ["zen-grid", DESKTOP_PREFIX, TABLET_PREFIX, MOBILE_PREFIX, GRID_COL_PREFIX];
export const getGridClasses = (className) => {
    const gridClasses = [];
    const restClasses = [];
    if (!className) {
        return {
            gridClasses,
            restClasses
        };
    }
    const classList = className.split(" ");
    classList.forEach(classItem => {
        if (gridClassPrefixes.some(prefix => classItem.startsWith(prefix))) {
            gridClasses.push(classItem);
        }
        else {
            restClasses.push(classItem);
        }
    });
    return {
        gridClasses,
        restClasses
    };
};
